detailed_optimizations.code_changes:
1) 函数签名增加 restrict 并使用 size_t：

void sparse_matvec(int n,
  const int * __restrict rowptr,
  const int * __restrict colidx,
  const double * __restrict values,
  const double * __restrict x,
  double * __restrict y)
{
  #pragma omp parallel for schedule(static)
  for (int i=0;i<n;i++) {
    double sum=0.0;
    int start=rowptr[i], end=rowptr[i+1];
    // 可选：对带状结构，x 访问近似顺序，可尝试预取
    for (int j=start;j<end;j++) {
      // __builtin_prefetch(&x[colidx[j+PREFDIST]], 0, 1);
      sum = fma(values[j], x[colidx[j]], sum);
    }
    y[i]=sum;
  }
}

2) 编译选项：-O3 -march=native -ffast-math(可选) -fopenmp；
3) 若允许改变数据结构：将 colidx 改为 32-bit 已是 int；values/x/y 保持 double；
4) 若矩阵行长度几乎固定（本例约 2*NONZER+1），可尝试按固定长度展开（见下一条）。

double dot_product(const double* __restrict x, const double* __restrict y, int n){
  double sum=0.0;
  #pragma omp parallel for reduction(+:sum) schedule(static)
  for(int i=0;i<n;i++) sum = fma(x[i], y[i], sum);
  return sum;
}

可选：链接 OpenBLAS/MKL：cblas_ddot(n,x,1,y,1)。

将每次迭代中的：
- x = x + alpha*p
- r = r - alpha*q
- rho_new = r'r
融合：

double rho_new=0.0;
#pragma omp parallel for reduction(+:rho_new) schedule(static)
for(int i=0;i<n;i++){
  x[i] = fma(alpha, p[i], x[i]);
  r[i] = fma(-alpha, q[i], r[i]);
  rho_new = fma(r[i], r[i], rho_new);
}

再将 p = r + beta*p 保持单独循环（或与下一次 SpMV 前的准备融合）。
同理，初始化阶段 r=b-q 与 p=r 可融合并顺便计算 rho：

double rho=0.0;
#pragma omp parallel for reduction(+:rho)
for i: r=b-q; p=r; rho+=r*r;

把 r/p/q 的分配移到 conj_grad 外部或改为传入工作区：

typedef struct { double *r,*p,*q; } cg_ws;

void conj_grad(..., cg_ws* ws){
  double* r=ws->r; double* p=ws->p; double* q=ws->q;
  // 不再 calloc/free
}

在 main 中一次性分配：
ws.r = aligned_alloc(64, n*sizeof(double));
ws.p = aligned_alloc(64, n*sizeof(double));
ws.q = aligned_alloc(64, n*sizeof(double));

并在每次调用前用 memset/循环清零需要清零的数组（通常 r/p/q 会被完全覆盖，不必清零）。

在 main 外层循环前分配一次：

double *ax = (double*)aligned_alloc(64, n*sizeof(double));

for(it=0;it<NITER;it++){
  conj_grad(...);
  sparse_matvec(..., x, ax);
  ...
}
free(ax);

并将 calloc 改为 malloc/aligned_alloc（无需清零）。
